#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 投行并购.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="投行并购"
DIM_COUNT=6

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (6 个):
  9.1 三层估值定位
  9.2 协同与控制权溢价压力测试
  9.3 成交确定性与监管时钟
  9.4 竞价结构与杠杆设计
  9.5 对手盘与 BATNA 测绘
  9.6 顾问利益冲突核查

背后的心智模型:
  • 三层价格——价值——成交价: 这行的人脑子里永远有三个数在打架——**内在价值** (DCF/现金流基本面) ⇄ **市场价格** (trading comps/情绪与动量) ⇄ **成交价** (含 control premiu
  • 价值创造 = 增长 × (ROIC − 资本成本): 价值只有一种创造方式——**以高于资本成本的回报率投资资本**；ROIC 低于资本成本时增长反而毁价，会计/财务工程/回购/EPS 目标都只是重新分配现金流，不创造价值 (conservation o
  • 估值纪律：synergy 显式化 + walk-away + winner's curse: synergy 与 control premium 必须**独立预测进现金流、举证责任在出价方**，且**绝不把全部协同价值当溢价付出去**；并购本质是拍卖，出价最高者通常对资产估值最高、因而最可能多

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "三层估值定位"
  "协同与控制权溢价压力测试"
  "成交确定性与监管时钟"
  "竞价结构与杠杆设计"
  "对手盘与 BATNA 测绘"
  "顾问利益冲突核查"
)
declare -a DIM_QUESTIONS=(
  "标的的内在价值 (DCF) / 市场价格 (trading comps) / 隐含成交价 (precedent 含控制权溢价) 三个数及其背离原因。"
  "synergy 拆成本/收入两类、是否显式进现金流、举证强度；control premium 是否被当\"惯例\"硬套。"
  "P(close) 的三大风险 (融资/反垄断重叠/MAC 宽窄) + HSR 阈值/CFIUS/EU 是否触发及时间表。"
  "该用 broad/limited/targeted/exclusive 哪种拍卖；信息闸 (teaser→…→exclusivity) 如何排布；exclusivity 何时关闸。"
  "谁是真买方/卖方对手 (战略 vs sponsor)、各自 walk-away/reservation price、谁的 BATNA 可执行。"
  "fairness opinion 出具方是否同时收 contingent fee / 有 buy-side 关系 / 持对手方股权 (El Paso/Del Monte 式)。"
)
declare -a DIM_SOURCES=(
  "SEC EDGAR (S-4/proxy 看历史成交)、Capital IQ/FactSet (comps/precedents)、Damodaran NYU 数据集 (WACC/multiple/ERP)。"
  "pitch/CIM 的 synergy 假设、Damodaran acquisition-valuation 讲义 (T01-S003)、可比交易的实付溢价。"
  "法律 client alert (Goodwin/Wachtell/Dechert，own publication)、FTC/Treasury/CFIUS 一手、SPA 的条件与 RTF/HOHW 条款。"
  "可比交易 proxy 的\"Background of the Merger\"过程记录 (EDGAR)、WSP sell-side 流程模板 (education vendor)。"
  "PitchBook/Mergermarket (sponsor 与 rumored 买家)、LBO 模型反推 sponsor 可付价、买家的 certainty posture。"
  "DEFM14A 的 fairness opinion 披露 + FINRA 5150 冲突披露 (EDGAR 一手)、engagement/fee letter 结构。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "一张 football field——三法区间 + 重叠可辩护区 + 当前背离一句话解释。"
  "协同的概率化区间 + \"不该当溢价全付\"的上限 + 一条 winner's curse 自查结论。"
  "\`board value ≈ price × P(close) − busted-cost − time-value\` 的定性排序 + 监管红线清单 (Decay risk: high，标核验日)。"
  "一条 auction 设计建议 (广度 + 闸序 + 何时授排他) + 对应保密性/价格权衡。"
  "对手盘地图 + 自己的 walk-away price + 用结构 (earnout/RWI/RTF) 而非价格破局的方案。"
  "冲突清单 + 是否需独立第二意见 + 该 opinion 的可信度折扣一句话。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
